-- CNB Primaria - Comunicación y Lenguaje L 1 - Cuarto, Quinto y Sexto Grado
-- Fuentes: .../Dosificación_de_los_aprendizajes_-_Área_de_Comunicación_y_Lenguaje_L_1_-_{Cuarto,Quinto,Sexto}_Grado
-- Nivel de detalle: competencia + sub-competencias

INSERT INTO competencias (grado, area, texto_completo, indicadores) VALUES
-- Cuarto Grado
('Cuarto Grado', 'Comunicación y Lenguaje L 1', '1. Interpreta mensajes escuchados en diferentes situaciones de comunicación social.', ARRAY['1.1. Identifica elementos importantes en mensajes escuchados en situaciones diversas de comunicación social.', '1.2. Demuestra comprensión de la información contenida en mensajes recibidos por medios audiovisuales: el teléfono, la radio, la televisión, entre otros.', '1.3. Organiza el contenido de los mensajes recibidos y la respuesta que dará a los mismos.']),
('Cuarto Grado', 'Comunicación y Lenguaje L 1', '2. Participa en intercambios comunicativos orales adecuando los mensajes que emite a la situación en que se encuentra.', ARRAY['2.1. Utiliza la modulación, la entonación y el timbre de la voz adecuados a la circunstancia comunicativa y al interlocutor o a los interlocutores.', '2.2. Organiza, en forma lógica y coherente, la información recibida en mensajes orales.', '2.3. Participa en situaciones comunicativas de manera responsable y respetuosa para establecer acuerdos y tomar decisiones.']),
('Cuarto Grado', 'Comunicación y Lenguaje L 1', '3. Interpreta mensajes verbales, textos icónicos e íconoverbales propios de su entorno sociocultural.', ARRAY['3.1. Establece la diferencia entre los diversos tipos de mensajes: visuales, auditivos, icónicos, entre otros.', '3.2. Interpreta la información explícita e infiere la información implícita presente en textos que presentan imagen y escritura.']),
('Cuarto Grado', 'Comunicación y Lenguaje L 1', '4. Aplica diferentes estrategias de lectura para obtener información y como recreación.', ARRAY['4.1. Interpreta, por medio de la lectura silenciosa, el significado de textos escritos y visuales.', '4.2. Aplica diferentes estrategias en la comprensión de textos informativos y literarios.', '4.3. Interpreta, por medio de la lectura oral y silenciosa, el significado de textos literarios e informativos.']),
('Cuarto Grado', 'Comunicación y Lenguaje L 1', '5. Produce textos informativos y con intención literaria de acuerdo con la estructura externa (forma) e interna (contenido).', ARRAY['5.1. Identifica el formato e intencionalidad de textos informativos.', '5.2. Redacta textos funcionales e informativos atendiendo los elementos que caracterizan la estructura externa de los mismos.', '5.3. Redacta textos narrativos y poéticos atendiendo los elementos que caracterizan la estructura externa de los mismos.', '5.4. Utiliza estructuras lingüísticas en la producción de diferentes tipos de texto.']),
('Cuarto Grado', 'Comunicación y Lenguaje L 1', '6. Utiliza estrategias para enriquecer su vocabulario básico.', ARRAY['6.1. Utiliza diversos significados de las palabras teniendo en cuenta la relación entre la estructura del idioma y el contexto sociocultural.', '6.2. Interpreta variaciones lingüísticas propias de su comunidad.']),
('Cuarto Grado', 'Comunicación y Lenguaje L 1', '7. Utiliza la normativa del idioma para el logro de una comunicación escrita eficaz.', ARRAY['7.1. Aplica, en los textos escritos, los elementos normativos emanados del estudio de los sonidos y de las palabras.', '7.2. Redacta oraciones de acuerdo a la normativa del idioma.', '7.3. Integra los aspectos formales de la lengua escrita, en los textos que produce.']),
('Cuarto Grado', 'Comunicación y Lenguaje L 1', '8. Organiza la información de acuerdo con las características estructurales, formales y de contenido de diferentes tipos de texto.', ARRAY['8.1. Organiza la información obtenida de diversas fuentes escritas.', '8.2. Utiliza tecnología de uso frecuente en el ambiente para obtener información.', '8.3. Utiliza diversos esquemas gráficos y modelos en la integración de información.']),

-- Quinto Grado
('Quinto Grado', 'Comunicación y Lenguaje L 1', '1. Interpreta diferentes tipos de mensajes orales que le orientan en la realización de un trabajo.', ARRAY['1.1. Identifica las palabras, en el lenguaje oral, que indican la secuencia a seguir en la realización de tareas.', '1.2. Selecciona términos que indican direccionalidad en el movimiento y que le facilitan la realización de tareas específicas.', '1.3. Determina los detalles importantes de la información transmitida oralmente y por medios de comunicación masiva para la organización de su trabajo.']),
('Quinto Grado', 'Comunicación y Lenguaje L 1', '2. Utiliza el lenguaje oral en el intercambio de ideas, información y opiniones.', ARRAY['2.1. Participa en distintas situaciones comunicativas expresando sus ideas con claridad y seguridad.', '2.2. Utiliza diferentes medios de comunicación para informar y expresar sus opiniones.', '2.3. Aplica las normas de cortesía en las diferentes modalidades de intercambio de información.']),
('Quinto Grado', 'Comunicación y Lenguaje L 1', '3. Produce mensajes verbales, no verbales, icónicos e ícono-verbales como apoyo a las actividades planeadas en los proyectos de aprendizaje.', ARRAY['3.1. Utiliza la información explícita e implícita que transmiten textos icónicos e ícono-verbales.', '3.2. Utiliza en su comunicación información por medio de signos y símbolos propios de su comunidad o región.']),
('Quinto Grado', 'Comunicación y Lenguaje L 1', '4. Lee textos y, con base en la estructura, el contenido y la finalidad de los diferentes tipos, selecciona los materiales que responden a sus necesidades.', ARRAY['4.1. Lee textos y utiliza la estructura de los diferentes tipos de texto en la selección de información pertinente.', '4.2. Reformula el contenido de los materiales leídos para seleccionar los que responden a sus necesidades.', '4.3. Evalúa la información seleccionada en función del trabajo que necesita realizar.']),
('Quinto Grado', 'Comunicación y Lenguaje L 1', '5. Produce textos informativos y con intención literaria de acuerdo con aspectos normativos y contenidos propios de la escritura de los idiomas.', ARRAY['5.1. Incluye, en su producción escrita, diferentes tipos de texto atendiendo a su estructura externa.', '5.2. Incluye en los textos que escribe elementos que señalan matices semánticos.', '5.3. Integra en los textos poéticos los rasgos propios del lenguaje figurado (asociaciones e identificaciones).']),
('Quinto Grado', 'Comunicación y Lenguaje L 1', '6. Utiliza el vocabulario adecuado en los diferentes tipos de lenguaje de acuerdo con las distintas culturas.', ARRAY['6.1. Utiliza el vocabulario específico atendiendo a la situación comunicativa y a la audiencia.', '6.2. Elabora textos atendiendo a la relación de significado entre las palabras.', '6.3. Utiliza, en eventos comunicativos, variaciones lingüísticas propias de su comunidad.']),
('Quinto Grado', 'Comunicación y Lenguaje L 1', '7. Utiliza las estructuras básicas y los elementos normativos del idioma materno en la comunicación oral y escrita.', ARRAY['7.1. Utiliza las diferentes categorías de palabras para ampliar el significado de su expresión oral y escrita.', '7.2. Utiliza palabras que funcionan como nexos y conectores en la redacción de textos breves.', '7.3. Integra la normativa del idioma en la producción de textos orales y escritos.']),
('Quinto Grado', 'Comunicación y Lenguaje L 1', '8. Utiliza estrategias que le permiten organizar la información esencial de fuentes escritas y tecnológicas.', ARRAY['8.1. Localiza la información pertinente en diversas fuentes escritas y audiovisuales.']),

-- Sexto Grado
('Sexto Grado', 'Comunicación y Lenguaje L 1', '1. Evalúa con actitud crítica la intencionalidad del mensaje: expositiva, argumentativa o normativa.', ARRAY['1.1. Identifica si el mensaje oral lleva una intención expositiva.', '1.2. Identifica si la intencionalidad del mensaje es argumentar sobre algún hecho o evento.', '1.3. Identifica si la intención del mensaje oral es establecer normas.']),
('Sexto Grado', 'Comunicación y Lenguaje L 1', '2. Argumenta en situaciones de comunicación oral utilizando un lenguaje adecuado a los interlocutores, al contenido y al contexto.', ARRAY['2.1. Expresa oralmente sus argumentos manteniéndose fiel a los temas tratados.', '2.2. Utiliza diferentes técnicas de comunicación oral en exposiciones de carácter argumentativo.', '2.3. Participa voluntariamente en eventos de libre expresión demostrando respeto por las personas con quienes interactúa.']),
('Sexto Grado', 'Comunicación y Lenguaje L 1', '3. Interpreta información transmitida por sistemas de comunicación verbal y no verbal y los procedimientos de persuasión y disuasión utilizados por los medios de comunicación masiva.', ARRAY['3.1. Interpreta los mensajes que se transmiten por los medios de comunicación y los compara con eventos de la vida cotidiana.', '3.2. Interpreta los símbolos y códigos cartográficos y de otra naturaleza utilizados frecuentemente en su comunidad y en el país.', '3.3. Interpreta la información explícita e implícita que transmiten los textos icónicos e ícono-verbales.', '3.4. Utiliza recursos tecnológicos para ampliar la información generada por medios de comunicación masiva.']),
('Sexto Grado', 'Comunicación y Lenguaje L 1', '4. Lee con sentido crítico identificando ideas y datos importantes que le permiten comunicarse de manera funcional e informarse, ampliar y profundizar sus conocimientos.', ARRAY['4.1. Aplica destrezas de lectura silenciosa al leer materiales en la adquisición de nuevos conocimientos.', '4.2. Aplica las destrezas de lectura que le permiten utilizar eficientemente la información necesaria.', '4.3. Determina la veracidad, relevancia y utilidad de la información según el tema que necesita abordar.', '4.4. Aplica destrezas de lectura para interpretar la información contenida en documentos legales.']),
('Sexto Grado', 'Comunicación y Lenguaje L 1', '5. Produce textos de diversos géneros, como medio de expresión, adaptados a requerimientos personales, escolares y socioculturales.', ARRAY['5.1. Identifica textos de diferentes géneros según su estructura externa.', '5.2. Incluye, en los textos que escribe, elementos que señalan matices semánticos.', '5.3. Integra en los textos que escribe, los rasgos propios del lenguaje figurado.', '5.4. Coopera en la generación grupal de textos recopilatorios propios de la tradición de su Pueblo o nación.']),
('Sexto Grado', 'Comunicación y Lenguaje L 1', '6. Aplica vocabulario amplio en diferentes situaciones comunicativas individuales y grupales.', ARRAY['6.1. Utiliza el vocabulario específico atendiendo a la situación comunicativa y a la audiencia.', '6.2. Elabora textos en su lengua materna atendiendo a diferentes intenciones y contextos comunicativos.', '6.3. Utiliza variaciones lingüísticas propias de su comunidad.']),
('Sexto Grado', 'Comunicación y Lenguaje L 1', '7. Expresa intenciones concretas de comunicación utilizando elementos normativos del lenguaje escrito.', ARRAY['7.1. Utiliza las diferentes categorías de palabras para ampliar el significado de su expresión oral y escrita.', '7.2. Integra los aspectos lexicales y gramaticales del idioma en la producción de textos orales y escritos.', '7.3. Aplica un proceso de revisión sistemática a los textos que produce para facilitar su comprensión.']),
('Sexto Grado', 'Comunicación y Lenguaje L 1', '8. Elabora textos de apoyo integrando datos obtenidos en las fuentes de información para la realización de actividades y tareas de aprendizaje.', ARRAY['8.1. Identifica las fuentes de información pertinentes en el proceso de elaboración de diferentes tareas.', '8.2. Aplica estrategias de investigación en la recolección de la información necesaria para la elaboración de diferentes tareas.', '8.3. Utiliza los recursos tecnológicos apropiados para apoyar la presentación de las tareas.']);
